import api from './api';


// GET MARKS
export const getMarks =
  async () => {

  const response =
    await api.get('/marks');

  return response.data;

};


// ADD MARKS
export const addMarks =
  async (data) => {

  const response =
    await api.post(
      '/marks',
      data
    );

  return response.data;

};
